/**
 * ORCHESTRATOR EXTENSION ‚ÄĒ Architecture & Debugging Guide
 * 
 * This extension turns pi into a pure orchestrator that delegates all work
 * to specialist subagents. The main agent never touches files directly.
 * 
 * COMPONENTS:
 * 1. Activity Feed System (lines 40-260)
 *    - Tracks subagent progress for real-time UX display
 *    - Zero token cost (onUpdate not persisted)
 *    - State: ActivityFeedState { goal, steps, currentStep }
 *    - Functions: createActivityFeed, parseTextForFeed, renderActivityFeed
 *    
 * 2. Specialist Definitions (lines 280-420)
 *    - scout, coder, reviewer, researcher, writer
 *    - Each has: name, tools[], model?, systemPrompt
 *    - systemPrompt includes ACTIVITY_FEED_INSTRUCTION for plan output
 *    
 * 3. In-Process Subagent Runner (lines 440-560)
 *    - runSubagent(): creates isolated AgentSession
 *    - Uses parent's modelRegistry for API key inheritance
 *    - Subscribes to session events ‚Üí updates activity feed
 *    
 * 4. Tool Handlers (lines 580-700)
 *    - delegate(): single specialist
 *    - parallel(): multiple specialists simultaneously
 *    - chain(): sequential with context passing
 * 
 * COMMON ISSUES:
 * - "No API key found" ‚Üí Check modelRegistry inheritance (line 460)
 * - Empty output ‚Üí Check specialist.tools includes needed tools
 * - Feed not updating ‚Üí Check event types in session.subscribe()
 * - Steps not parsing ‚Üí Check ## Goal / ## Steps format in prompt
 * 
 * ACTIVITY FEED FLOW:
 * 1. Subagent starts ‚Üí parseTextForFeed extracts goal + steps
 * 2. tool_call event ‚Üí addSubstep (auto-detects tool type)
 * 3. tool_result event ‚Üí completeLastSubstep
 * 4. message_end event ‚Üí completeCurrentStep, advance to next
 * 5. renderActivityFeed ‚Üí formats for UI display
 */

import { getModel } from "@earendil-works/pi-ai";
import {
	AuthStorage,
	createAgentSession,
	createExtensionRuntime,
	DefaultResourceLoader,
	type ExtensionAPI,
	getAgentDir,
	ModelRegistry,
	type ResourceLoader,
	SessionManager,
} from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";
import { Container, type Component, Text, type TUI } from "@earendil-works/pi-tui";
import { shortenLabel } from "./token-saver.ts";
import { appendFileSync, mkdirSync } from "node:fs";
import { join } from "node:path";

const DEBUG_LOG_DIR = "/tmp/orchestrator-debug";
try { mkdirSync(DEBUG_LOG_DIR, { recursive: true }); } catch {}
const DEBUG_LOG = join(DEBUG_LOG_DIR, `orchestrator-${Date.now()}.log`);

function debugLog(msg: string, data?: any): void {
	const line = data ? `[${new Date().toISOString()}] ${msg} ${JSON.stringify(data)}` : `[${new Date().toISOString()}] ${msg}`;
	try { appendFileSync(DEBUG_LOG, line + "\n"); } catch {}
}

// ============================================================================
// Config
// ============================================================================

/**
 * Module-level orchestrator activity state.
 * Persists across multiple delegate/parallel/chain calls in a session.
 * Reset on new session via before_agent_start handler.
 */
let orchestratorActivity: OrchestratorActivity | null = null;
let orchestratorGoal: string = "";

function getOrchestratorActivity(taskDescription?: string): OrchestratorActivity {
	// Create fresh activity for each new tool call to avoid stale state
	if (!orchestratorActivity) {
		orchestratorActivity = createOrchestratorActivity();
	}
	if (taskDescription && !orchestratorGoal) {
		orchestratorGoal = shortenLabel(taskDescription);
	}
	return orchestratorActivity;
}

/** Reset orchestrator activity (called at start of each tool execute) */
function resetOrchestratorActivity(): void {
	orchestratorActivity = createOrchestratorActivity();
	orchestratorGoal = "";
	lastActivityFeedText = "";
}

const MAX_PARALLEL = 4;
const OUTPUT_CAP = 30_000; // bytes per subagent output fed back to main
const BOX_INNER_WIDTH = 52; // inner content width for tool block boxes

// ============================================================================
// Plan Panel ‚ÄĒ persistent header widget (setHeader)
// ============================================================================

/**
 * Plan panel state: the goal, steps, and timing for the Orchestration Plan header.
 * Set when delegate/parallel/chain is called. Cleared on before_agent_start.
 */
let planState: {
	goal: string;
	steps: Array<{ label: string; completed: boolean; active: boolean }>;
	startTime: number;
} | null = null;

let planContainer: Container | null = null;
let planTimer: ReturnType<typeof setInterval> | null = null;
let planTUI: TUI | null = null;

/**
 * Last rendered activity feed text.
 * Stored so renderResult can show it on final (non-partial) render.
 */
let lastActivityFeedText: string = "";

function buildPlanPanel(tui: TUI, theme: any): Container {
	// Reuse existing container so timer updates affect the SAME instance the TUI holds
	if (!planContainer) {
		planContainer = new Container();
	}
	planTUI = tui;
	renderPlanPanel();
	return planContainer;
}

function renderPlanPanel(): void {
	if (!planContainer || !planState) return;
	const { goal, steps, startTime } = planState;
	const elapsed = Date.now() - startTime;
	const elapsedStr = formatDuration(elapsed);

	const total = steps.length;
	const completed = steps.filter((s) => s.completed).length;

	const boxWidth = Math.max(goal.length + 4, 34);
	const padding = boxWidth - 4;
	const truncated = goal.length > padding ? goal.slice(0, padding - 3) + "..." : goal;
	const pad = padding - truncated.length;

	const dots = steps.map((s) => s.completed ? "‚óŹ" : s.active ? "‚óŹ" : "‚óč").join("");

	planContainer.clear();

	planContainer.addChild(new Text(`‚ĒĆ‚ĒÄ Orchestration Plan ${("‚ĒÄ").repeat(Math.max(0, boxWidth - 21))}‚Ēź`, 0, 0));
	planContainer.addChild(new Text(`‚Ēā Goal: ${truncated}${(" ").repeat(pad)} ‚Ēā`, 0, 0));

	for (const step of steps) {
		const icon = step.completed ? "‚úď" : step.active ? "‚†č" : "‚óč";
		const label = step.label.length > padding ? step.label.slice(0, padding - 3) + "..." : step.label;
		planContainer.addChild(new Text(`‚Ēā  ${icon} ${label}${(" ").repeat(Math.max(0, padding - label.length - 2))} ‚Ēā`, 0, 0));
	}

	planContainer.addChild(new Text(`‚Ēā  ${dots} [${completed}/${total}]      ‚ÄĘ    Elapsed: ${elapsedStr}${(" ").repeat(Math.max(0, 6))} ‚Ēā`, 0, 0));
	planContainer.addChild(new Text(`‚ĒĒ${("‚ĒÄ").repeat(boxWidth)}‚Ēė`, 0, 0));
}

function updatePlanDisplay(): void {
	renderPlanPanel();
	if (planContainer) planContainer.invalidate();
	if (planTUI) planTUI.requestRender();
}

function startPlanTimer(): void {
	stopPlanTimer();
	planTimer = setInterval(() => {
		if (planState && planContainer) {
			updatePlanDisplay();
		} else {
			stopPlanTimer();
		}
	}, 1000);
}

function stopPlanTimer(): void {
	if (planTimer !== null) {
		clearInterval(planTimer);
		planTimer = null;
	}
}

function clearPlanPanel(ctx: { ui: { setHeader: (f: any) => void }; mode?: string }): void {
	stopPlanTimer();
	planState = null;
	planContainer = null;
	planTUI = null;
	lastActivityFeedText = "";
	if (ctx.mode === "tui") {
		ctx.ui.setHeader(undefined);
	}
}

function setupPlanPanel(goal: string, stepLabels: string[], ctx: { ui: { setHeader: (f: any) => void }; mode?: string }): void {
	planState = {
		goal,
		steps: stepLabels.map((label, i) => ({
			label,
			completed: false,
			active: i === 0,
		})),
		startTime: Date.now(),
	};
	if (ctx.mode === "tui") {
		ctx.ui.setHeader((tui: TUI, theme: any) => buildPlanPanel(tui, theme));
	}
	startPlanTimer();
	updatePlanDisplay();
}

function completePlanStep(ctx: { ui: { setHeader: (f: any) => void }; mode?: string }): void {
	if (!planState) return;
	const idx = planState.steps.findIndex((s) => s.active);
	if (idx >= 0) {
		planState.steps[idx].completed = true;
		planState.steps[idx].active = false;
	}
	const next = idx + 1;
	if (next < planState.steps.length) {
		planState.steps[next].active = true;
	}
	updatePlanDisplay();
}

// ============================================================================
// Orchestrator Activity ‚ÄĒ high-level progress view for user
// ============================================================================

/**
 * OrchestratorActivity ‚ÄĒ tracks overall task progress
 * 
 * This is the USER-FACING progress view. It shows:
 *   - Overall progress [N/M]
 *   - Current step with arrow ‚Üí
 *   - Completed steps with checkmark ‚úď and timing
 *   - Pending steps with circle ‚óč
 * 
 * NO specialist names shown ‚ÄĒ just task progress.
 * 
 * Format:
 *   [3/6] ‚Üí Create package.json (2m 15s)
 *     ‚úď Read pi extensions docs (12s)
 *     ‚úď Read CloakBrowser README (8s)
 *     ‚úď Analyze API patterns (45s)
 *     ‚Üí Create package.json
 *     ‚óč Write index.ts
 *     ‚óč Test extension
 */

interface OrchestratorStep {
	label: string;
	completed: boolean;
	startTime?: number;
	endTime?: number;
}

interface OrchestratorActivity {
	steps: OrchestratorStep[];
	currentStep: number;
	startTime: number;
}

function createOrchestratorActivity(): OrchestratorActivity {
	return {
		steps: [],
		currentStep: -1,
		startTime: Date.now(),
	};
}

function addOrchestratorStep(activity: OrchestratorActivity, label: string): void {
	const cleanLabel = shortenLabel(label);
	// Avoid duplicates
	if (activity.steps.some((s) => s.label === cleanLabel)) return;
	activity.steps.push({
		label: cleanLabel,
		completed: false,
		startTime: Date.now(),
	});
	if (activity.currentStep === -1) activity.currentStep = 0;
}

function completeOrchestratorStep(activity: OrchestratorActivity): void {
	if (activity.currentStep < 0 || activity.currentStep >= activity.steps.length) return;
	activity.steps[activity.currentStep].completed = true;
	activity.steps[activity.currentStep].endTime = Date.now();
	activity.currentStep++;
}

