	activity.steps[activity.currentStep].completed = true;
	activity.steps[activity.currentStep].endTime = Date.now();
	activity.currentStep++;
}

function formatDuration(ms: number): string {
	if (ms < 1000) return `${ms}ms`;
	const seconds = Math.floor(ms / 1000);
	if (seconds < 60) return `${seconds}s`;
	const minutes = Math.floor(seconds / 60);
	const remainingSeconds = seconds % 60;
	return remainingSeconds > 0 ? `${minutes}m ${remainingSeconds}s` : `${minutes}m`;
}

/**
 * Render the orchestrator activity feed.
 * 
 * Format:
 *   ‚ĒĆ‚ĒÄ Task ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚Ēź
 *   ‚Ēā Task description here               ‚Ēā
 *   ‚ĒĒ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚Ēė
 *   ‚óŹ‚óŹ‚óŹ‚óč‚óč‚óč [3/6]
 *   ‚úď Read pi extensions docs (12s)
 *   ‚úď Read CloakBrowser README (8s)
 *   ‚†č Analyze API patterns...
 *   ‚óč Create package.json
 *   ‚óč Write index.ts
 *   ‚óč Test extension
 */
function renderOrchestratorActivity(activity: OrchestratorActivity, goal?: string): string {
	const lines: string[] = [];
	const total = activity.steps.length;
	const completed = activity.steps.filter((s) => s.completed).length;

	if (goal) {
		const boxWidth = Math.max(goal.length + 4, 30);
		const padding = boxWidth - 4;
		const truncated = goal.length > padding ? goal.slice(0, padding - 3) + "..." : goal;
		const pad = padding - truncated.length;
		lines.push(`‚ĒĆ‚ĒÄ Task ${"‚ĒÄ".repeat(boxWidth - 7)}‚Ēź`);
		lines.push(`‚Ēā ${truncated}${" ".repeat(pad)} ‚Ēā`);
		lines.push(`‚ĒĒ${"‚ĒÄ".repeat(boxWidth - 2)}‚Ēė`);
	}

	const dots = activity.steps.map((s, i) => {
		if (s.completed) return "‚óŹ";
		if (i === activity.currentStep) return "‚óŹ";
		return "‚óč";
	}).join("");
	lines.push(`${dots} [${completed}/${total}]`);

	for (let i = 0; i < total; i++) {
		const step = activity.steps[i];
		const isCurrent = i === activity.currentStep;

		if (step.completed) {
			const duration = step.startTime && step.endTime
				? formatDuration(step.endTime - step.startTime)
				: "";
			lines.push(`‚úď ${step.label}${duration ? ` (${duration})` : ""}`);
		} else if (isCurrent) {
			lines.push(`‚†č ${step.label}...`);
		} else {
			lines.push(`‚óč ${step.label}`);
		}
	}

	return lines.join("\n");
}

/**
 * Render combined orchestrator + subagent progress.
 * Shows overall task progress with the current step's subtasks indented.
 */
function renderCombinedProgress(
	orchestratorActivity: OrchestratorActivity,
	specialistName: string,
	feedState: ActivityFeedState,
	goal?: string,
): string {
	const lines: string[] = [];
	const total = orchestratorActivity.steps.length;
	const completed = orchestratorActivity.steps.filter((s) => s.completed).length;

	// Boxed header with goal
	if (goal) {
		const boxWidth = Math.max(goal.length + 4, 30);
		const padding = boxWidth - 4;
		const truncated = goal.length > padding ? goal.slice(0, padding - 3) + "..." : goal;
		const pad = padding - truncated.length;
		lines.push(`‚ĒĆ‚ĒÄ Task ${"‚ĒÄ".repeat(boxWidth - 7)}‚Ēź`);
		lines.push(`‚Ēā ${truncated}${" ".repeat(pad)} ‚Ēā`);
		lines.push(`‚ĒĒ${"‚ĒÄ".repeat(boxWidth - 2)}‚Ēė`);
	}

	// Progress dots
	const dots = orchestratorActivity.steps.map((s, i) => {
		if (s.completed) return "‚óŹ";
		if (i === orchestratorActivity.currentStep) return "‚óŹ";
		return "‚óč";
	}).join("");
	lines.push(`${dots} [${completed}/${total}]`);

	// Steps list
	for (let i = 0; i < total; i++) {
		const step = orchestratorActivity.steps[i];
		const isCurrent = i === orchestratorActivity.currentStep;
		const isPending = !step.completed && !isCurrent;

		if (step.completed) {
			const duration = step.startTime && step.endTime
				? formatDuration(step.endTime - step.startTime)
				: "";
			lines.push(`‚úď ${step.label}${duration ? ` (${duration})` : ""}`);
		} else if (isCurrent) {
			lines.push(`‚Üí ${step.label}... [${specialistName}]`);
			// Show subagent's subtasks indented under current step
			if (feedState.steps.length > 0 && feedState.currentStep >= 0 && feedState.currentStep < feedState.steps.length) {
				const currentFeedStep = feedState.steps[feedState.currentStep];
				for (const sub of currentFeedStep.substeps) {
					lines.push(sub.completed ? `  ‚úď ${sub.label}` : `  ‚†č ${sub.label}...`);
				}
			} else {
				lines.push(`  ‚†č Starting...`);
			}
		} else if (isPending) {
			lines.push(`‚óč ${step.label}`);
		}
	}

	return lines.join("\n");
}

// ============================================================================
// Activity Feed ‚ÄĒ tracks subagent progress for UX display
// ============================================================================

/**
 * Activity Feed State
 * 
 * Tracks the subagent's work progress for real-time UX display.
 * Updated via text deltas and tool calls from the subagent session.
 * 
 * Structure:
 *   goal: string           - One-line description of the task
 *   steps: Step[]          - Main steps (defined by subagent or parsed)
 *   currentStep: number    - Index of currently active step
 *   substeps: Substep[]    - Dynamic substeps under current main step
 * 
 * Parsing:
 *   - ## Goal\n<text> ‚Üí sets goal
 *   - ## Steps\n- <text> ‚Üí adds main steps
 *   - Tool calls (read/grep/bash) ‚Üí adds substeps
 *   - message_end ‚Üí marks current step complete
 * 
 * Display:
 *   ‚úď = completed, ‚Üí = in progress, ‚óč = pending
 *   Completed main steps show substep count: "‚úď Step (N items)"
 *   Current step shows last 2 substeps
 */

interface Substep {
	label: string;
	completed: boolean;
}

interface Step {
	label: string;
	completed: boolean;
	substeps: Substep[];
}

interface ActivityFeedState {
	goal: string;
	steps: Step[];
	currentStep: number;
}

function createActivityFeed(): ActivityFeedState {
	return {
		goal: "",
		steps: [],
		currentStep: -1,
	};
}

/**
 * Parse subagent text output to extract goal and steps.
 * Called on each text_delta to update the feed incrementally.
 */
function parseTextForFeed(state: ActivityFeedState, text: string): void {
	const lines = text.split("\n");
	for (const line of lines) {
		const trimmed = line.trim();
		if (trimmed.startsWith("## Goal")) {
			// Next non-empty line is the goal
			state.goal = ""; // Will be set on next line
		} else if (trimmed.startsWith("## Steps")) {
			// Subsequent "- " lines are steps
		} else if (trimmed.startsWith("- ") && state.goal && state.steps.length === 0) {
			// First "- " after goal = first step
			addStep(state, trimmed.slice(2));
		} else if (trimmed.startsWith("- ") && state.steps.length > 0) {
			addStep(state, trimmed.slice(2));
		} else if (state.goal === "" && trimmed.length > 0 && !trimmed.startsWith("#")) {
			state.goal = trimmed;
		}
	}
}

function addStep(state: ActivityFeedState, label: string): void {
	// Avoid duplicates
	if (state.steps.some((s) => s.label === label)) return;
	state.steps.push({ label, completed: false, substeps: [] });
	if (state.currentStep === -1) state.currentStep = 0;
}

/**
 * Add a substep to the current main step.
 * Called when a tool_call event is detected.
 */
function addSubstep(state: ActivityFeedState, label: string): void {
	if (state.currentStep < 0 || state.currentStep >= state.steps.length) return;
	const step = state.steps[state.currentStep];
	// Avoid duplicates
	if (step.substeps.some((s) => s.label === label)) return;
	step.substeps.push({ label, completed: false });
}

/**
 * Mark the current step's last substep as complete.
 */
function completeLastSubstep(state: ActivityFeedState): void {
	if (state.currentStep < 0 || state.currentStep >= state.steps.length) return;
	const step = state.steps[state.currentStep];
	if (step.substeps.length > 0) {
		step.substeps[step.substeps.length - 1].completed = true;
	}
}

/**
 * Mark current step as complete, advance to next.
 */
function completeCurrentStep(state: ActivityFeedState): void {
	if (state.currentStep < 0 || state.currentStep >= state.steps.length) return;
	// Complete any pending substeps
	for (const sub of state.steps[state.currentStep].substeps) {
		sub.completed = true;
	}
	state.steps[state.currentStep].completed = true;
	state.currentStep++;
}

/**
 * Auto-detect substep from tool call.
 * Maps tool names to human-readable labels.
 */
function toolCallToSubstep(toolName: string, input: any): string {
	switch (toolName) {
		case "read":
			return `Reading ${input?.path || "file"}`;
		case "bash":
			return `Running: ${(input?.command || "...").slice(0, 40)}`;
		case "grep":
			return `Searching: ${input?.pattern || "..."}`;
		case "find":
			return `Finding: ${input?.pattern || "..."}`;
		case "edit":
			return `Editing ${input?.path || "file"}`;
		case "write":
			return `Writing ${input?.path || "file"}`;
		default:
			return `Using ${toolName}`;
	}
}

/**
 * Render the subagent activity feed.
 * 
 * Cache-safe: only used in onUpdate (display-only), not persisted.
 * 
 * Format (indented under orchestrator):
 *   ‚úď README.md (4s)
 *   ‚†č examples.md...
 *   ‚óč package.json
 * 
 * Shows ONLY current step's subtasks in chronological order.
 * Completed subtasks at top, current in middle, pending at bottom.
 */
function renderActivityFeed(name: string, state: ActivityFeedState): string {
	const lines: string[] = [];

	// If no steps yet, show starting
	if (state.steps.length === 0) {
		lines.push(`  ‚†č Starting...`);
		return lines.join("\n");
	}

	const total = state.steps.length;
	const completed = state.steps.filter((s) => s.completed).length;

	// Task box with goal
	if (state.goal) {
		const boxWidth = Math.max(state.goal.length + 4, 30);
		const padding = boxWidth - 4;
		const truncated = state.goal.length > padding ? state.goal.slice(0, padding - 3) + "..." : state.goal;
		const pad = padding - truncated.length;
		lines.push(`‚ĒĆ‚ĒÄ Task ${("‚ĒÄ").repeat(Math.max(0, boxWidth - 7))}‚Ēź`);
		lines.push(`‚Ēā ${truncated}${(" ").repeat(pad)} ‚Ēā`);
		lines.push(`‚ĒĒ${("‚ĒÄ").repeat(Math.max(0, boxWidth - 2))}‚Ēė`);
	}

	// Progress dots
	const dots = state.steps.map((s, i) => {
		if (s.completed) return "‚óŹ";
		if (i === state.currentStep) return "‚óŹ";
		return "‚óč";
	}).join("");
	lines.push(`${dots} [${completed}/${total}]`);

	// Steps list
	for (let i = 0; i < total; i++) {
		const step = state.steps[i];
		const isCurrent = i === state.currentStep;

		if (step.completed) {
			lines.push(`‚úď ${step.label}`);
		} else if (isCurrent) {
			lines.push(`‚†č ${step.label}...`);
			// Show substeps indented under current step
			for (const sub of step.substeps) {
				lines.push(sub.completed ? `  ‚úď ${sub.label}` : `  ‚†č ${sub.label}...`);
			}
		} else {
			lines.push(`‚óč ${step.label}`);
		}
	}

	return lines.join("\n");
}

// ============================================================================
// Compression ‚ÄĒ applied to ALL subagent output before returning to main agent
// ==============================================================================

const ANSI_RE = /\x1b\[[0-9;]*[a-zA-Z]/g;

/**
 * Compress subagent output for token savings.
 * 
 * Cache-safe: compression happens BEFORE output enters parent context.
 * Delegates to token-saver's compression logic for consistency.
 */
function compressOutput(output: string): string {
	let result = output;

	// Strip ANSI color codes
	result = result.replace(ANSI_RE, "");

	// Collapse triple+ blank lines
	result = result.replace(/\n{3,}/g, "\n\n");

	// Trim leading/trailing whitespace
	result = result.trim();

	return result;
}

