	// ‚ĒÄ‚ĒÄ Box-wrapping helpers (standalone functions, no `this` binding issues) ‚ĒÄ‚ĒÄ

	function wrapInBox(lines: string[], boxWidth: number): string {
		const out: string[] = [];
		for (const line of lines) {
			const clean = line.replace(/\x1b\[[0-9;]*m/g, "");
			const padded = clean.length > boxWidth - 4
				? clean.slice(0, boxWidth - 4)
				: clean + " ".repeat(boxWidth - 4 - clean.length);
			out.push(`‚Ēā ${padded} ‚Ēā`);
		}
		out.push(`‚ēį${("‚ĒÄ").repeat(boxWidth - 2)}‚ēĮ`);
		return out.join("\n");
	}

	function boxWidthFor(name: string): number {
		if (!name) return 0;
		return 3 + name.length + 1 + Math.max(0, BOX_INNER_WIDTH - name.length) + 1;
	}

	function specDisplayName(params: any, details: any): string {
		const raw = params?.specialist || details?.specialist || "";
		return raw ? raw.charAt(0).toUpperCase() + raw.slice(1) : "";
	}

	// ‚ĒÄ‚ĒÄ Tool: delegate ‚ÄĒ Single, parallel, or chain mode ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ

