			}
			if (args.steps) {
				const names = args.steps.map((s: any) => s.specialist).join(" ‚Üí ");
				return new Text(theme.fg("toolTitle", theme.bold(`‚Üí chain `)) + theme.fg("dim", names), 0, 0);
			}
			return new Text(theme.fg("toolTitle", theme.bold(`‚Üí `)) + theme.fg("accent", args.specialist || "?"), 0, 0);
