			const ctxParams = (context as any)?.params as Record<string, any> | undefined;
			const content = result.content?.[0];
			const text = content?.type === "text" ? content.text : "";

			const specName = specDisplayName(ctxParams, details);
			const bWidth = boxWidthFor(specName);

			if (isPartial) {
				if (text && bWidth > 0) {
					return new Text(theme.fg("warning", wrapInBox(text.split("\n"), bWidth)), 0, 0);
				}
				if (details?.specialist && bWidth > 0) {
					return new Text(theme.fg("warning", wrapInBox([`‚†č ${details.specialist}...`], bWidth)), 0, 0);
				}
