// ============================================================================
// Orchestrator Activity ‚ÄĒ high-level progress view for user
// ============================================================================

/**
 * OrchestratorActivity ‚ÄĒ tracks overall task progress
 * 
 * This is the USER-FACING progress view. It shows:
 *   - Overall progress [N/M]
 *   - Current step with arrow ‚Üí
 *   - Completed steps with checkmark ‚úď and timing
 *   - Pending steps with circle ‚óč
 * 
 * NO specialist names shown ‚ÄĒ just task progress.
 * 
 * Format:
 *   [3/6] ‚Üí Create package.json (2m 15s)
 *     ‚úď Read pi extensions docs (12s)
 *     ‚úď Read CloakBrowser README (8s)
 *     ‚úď Analyze API patterns (45s)
 *     ‚Üí Create package.json
 *     ‚óč Write index.ts
 *     ‚óč Test extension
 */

interface OrchestratorStep {
	label: string;
	completed: boolean;
	startTime?: number;
	endTime?: number;
}

interface OrchestratorActivity {
	steps: OrchestratorStep[];
	currentStep: number;
	startTime: number;
}

function createOrchestratorActivity(): OrchestratorActivity {
	return {
		steps: [],
		currentStep: -1,
		startTime: Date.now(),
	};
}

function addOrchestratorStep(activity: OrchestratorActivity, label: string): void {
	const cleanLabel = shortenLabel(label);
	// Avoid duplicates
	if (activity.steps.some((s) => s.label === cleanLabel)) return;
	activity.steps.push({
		label: cleanLabel,
		completed: false,
		startTime: Date.now(),
	});
	if (activity.currentStep === -1) activity.currentStep = 0;
}

function completeOrchestratorStep(activity: OrchestratorActivity): void {
	if (activity.currentStep < 0 || activity.currentStep >= activity.steps.length) return;
	activity.steps[activity.currentStep].completed = true;
	activity.steps[activity.currentStep].endTime = Date.now();
	activity.currentStep++;
}

function formatDuration(ms: number): string {
	if (ms < 1000) return `${ms}ms`;
	const seconds = Math.floor(ms / 1000);
	if (seconds < 60) return `${seconds}s`;
	const minutes = Math.floor(seconds / 60);
	const remainingSeconds = seconds % 60;
	return remainingSeconds > 0 ? `${minutes}m ${remainingSeconds}s` : `${minutes}m`;
}

