		const icon = step.completed ? "‚úď" : step.active ? "‚†č" : "‚óč";
		const label = step.label.length > padding ? step.label.slice(0, padding - 3) + "..." : step.label;
		planContainer.addChild(new Text(`‚Ēā  ${icon} ${label}${(" ").repeat(Math.max(0, padding - label.length - 2))} ‚Ēā`, 0, 0));
	}

	planContainer.addChild(new Text(`‚Ēā  ${dots} [${completed}/${total}]      ‚ÄĘ    Elapsed: ${elapsedStr}${(" ").repeat(Math.max(0, 6))} ‚Ēā`, 0, 0));
	planContainer.addChild(new Text(`‚ĒĒ${("‚ĒÄ").repeat(boxWidth)}‚Ēė`, 0, 0));
}

function updatePlanDisplay(): void {
	renderPlanPanel();
	if (planContainer) planContainer.invalidate();
	if (planTUI) planTUI.requestRender();
	// Non-TUI fallback: push status text
	if (_planStatusFn) {
		_planStatusFn("orchestrator", renderPlanStatusText());
	}
}

function startPlanTimer(): void {
	stopPlanTimer();
	planTimer = setInterval(() => {
		if (planState && planContainer) {
			updatePlanDisplay();
		} else {
			stopPlanTimer();
		}
	}, 1000);
}

function stopPlanTimer(): void {
	if (planTimer !== null) {
		clearInterval(planTimer);
		planTimer = null;
	}
}

function clearPlanPanel(ctx: { ui: { setHeader: (f: any) => void; setStatus?: (id: string, text: string) => void }; mode?: string }): void {
	stopPlanTimer();
	planState = null;
	planContainer = null;
	planTUI = null;
	lastActivityFeedText = "";
	_planStatusFn = null;
	if (ctx.mode === "tui") {
		ctx.ui.setHeader(undefined);
	} else if (ctx.ui.setStatus) {
		ctx.ui.setStatus("orchestrator", "");
	}
}

function setupPlanPanel(goal: string, stepLabels: string[], ctx: { ui: { setHeader: (f: any) => void; setStatus?: (id: string, text: string) => void }; mode?: string }): void {
	planState = {
		goal,
		steps: stepLabels.map((label, i) => ({
			label,
			completed: false,
			active: i === 0,
		})),
		startTime: Date.now(),
	};
	if (ctx.mode === "tui") {
		ctx.ui.setHeader((tui: TUI, theme: any) => buildPlanPanel(tui, theme));
		_planStatusFn = null;
	} else if (ctx.ui.setStatus) {
		_planStatusFn = ctx.ui.setStatus.bind(ctx.ui);
	} else {
		_planStatusFn = null;
	}
	startPlanTimer();
	updatePlanDisplay();
}

function completePlanStep(ctx: { ui: { setHeader: (f: any) => void; setStatus?: (id: string, text: string) => void }; mode?: string }): void {
	if (!planState) return;
	const idx = planState.steps.findIndex((s) => s.active);
	if (idx >= 0) {
		planState.steps[idx].completed = true;
		planState.steps[idx].active = false;
	}
	const next = idx + 1;
	if (next < planState.steps.length) {
		planState.steps[next].active = true;
	}
	updatePlanDisplay();
}

