function completePlanStep(ctx: { ui: { setHeader: (f: any) => void; setStatus?: (id: string, text: string) => void }; mode?: string }): void {
	if (!planState) return;
	const idx = planState.steps.findIndex((s) => s.active);
	if (idx >= 0) {
		planState.steps[idx].completed = true;
		planState.steps[idx].errored = false;
		planState.steps[idx].active = false;
	}
	const next = idx + 1;
	if (next < planState.steps.length) {
		planState.steps[next].active = true;
	}
	updatePlanDisplay();
}

/** Mark the current plan step as errored (keeps active state so progress stops) */
function errorPlanStep(ctx: { ui: { setHeader: (f: any) => void; setStatus?: (id: string, text: string) => void }; mode?: string }): void {
	if (!planState) return;
	const idx = planState.steps.findIndex((s) => s.active);
	if (idx >= 0) {
		planState.steps[idx].errored = true;
		planState.steps[idx].active = false;
		// Don't advance to next step ‚ÄĒ pipeline stops on error
	}
	updatePlanDisplay();
}

